/*eslint-disable*/
import React from "react";
import { Link } from "react-router-dom";
import RestaurantCard from "components/Common/restaurantCard.js";

export default function AuthNavbar(props) {
  const [navbarOpen, setNavbarOpen] = React.useState(false);
  const [sidebarOpen, setSidebarOpen] = React.useState(false);
  const [showLogoutConfirm, setShowLogoutConfirm] = React.useState(false);
  
  // ==================== STATE لعروض العمل ====================
  const [showJobOffers, setShowJobOffers] = React.useState(false);
  const [showNotification, setShowNotification] = React.useState(false);
  const [notificationMessage, setNotificationMessage] = React.useState("");
  
  // ==================== بيانات عروض العمل ====================
  const [jobOffers, setJobOffers] = React.useState([
    {
      id: 1,
      name: "Le Gourmet Parisien",
      icon: "🍽️",
      location: "Paris 8ème, France",
      position: "Serveuse",
      salary: "28,000 DA/mois",
      hours: "18:00 - 23:00",
      description: "Restaurant gastronomique cherche serveuse expérimentée pour service du soir.",
      benefits: ["Repas inclus", "Pourboires", "Formation continue"]
    },
    {
      id: 2,
      name: "Café de la Paix",
      icon: "🍸",
      location: "Lyon Centre, France",
      position: "Barmaid",
      salary: "25,000 DA/mois",
      hours: "15:00 - 22:00",
      description: "Café branché cherche barmaid créative pour cocktails et service bar.",
      benefits: ["Prime", "Équipe jeune", "Pourboires"]
    },
    {
      id: 3,
      name: "Sushi Master",
      icon: "🍣",
      location: "Marseille, France",
      position: "Serveuse polyvalente",
      salary: "26,000 DA/mois",
      hours: "11:30 - 14:30 / 19:00 - 22:30",
      description: "Restaurant japonais cherche serveuse dynamique.",
      benefits: ["Repas offerts", "CDI possible", "Parking"]
    }
  ]);

  // ==================== بيانات البروفيل مع رفع الصور من الجهاز ====================
  const [tempProfile, setTempProfile] = React.useState({
    name: "Jenna",
    lastName: "Stones",
    role: "Serveuse / Barmaid",
    location: "Paris, France",
    phone: "+33 6 12 34 56 78",
    workTime: "Lundi - Samedi: 10:00 - 19:00",
    bio: "Serveuse professionnelle avec 5 ans d'expérience dans la restauration.",
    coverImage: null, // ستكون من الجهاز
    profileImage: null, // ستكون من الجهاز
    email: "jenna.stones@example.com",
    skills: ["Service client", "Gestion des commandes", "Polyvalence", "Anglais courant"]
  });

  // ==================== معاينة الصور ====================
  const [coverPreview, setCoverPreview] = React.useState(null);
  const [profilePreview, setProfilePreview] = React.useState(null);

  // ==================== دوال رفع الصور ====================
  const handleCoverImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setCoverPreview(reader.result);
        setTempProfile({ ...tempProfile, coverImage: reader.result });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleProfileImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setProfilePreview(reader.result);
        setTempProfile({ ...tempProfile, profileImage: reader.result });
      };
      reader.readAsDataURL(file);
    }
  };

  // ==================== Liens sociaux ====================
  const [socialLinks, setSocialLinks] = React.useState({
    facebook: "",
    instagram: "",
    twitter: "",
    linkedin: "",
    tiktok: ""
  });

  // ==================== Fonctions ====================
  const handleLogout = () => {
    setShowLogoutConfirm(false);
    alert("👋 Vous êtes déconnecté");
  };

  const saveProfileSettings = () => {
    alert("✅ Profil mis à jour avec succès!");
    setSidebarOpen(false);
  };

  const updateSocialLink = (platform, url) => {
    setSocialLinks({ ...socialLinks, [platform]: url });
  };

  const saveSocialLinks = () => {
    alert("✅ Liens sociaux mis à jour!");
    setSidebarOpen(false);
  };

  // ==================== Fonctions pour les offres d'emploi ====================
  const showNotificationMessage = (message) => {
    setNotificationMessage(message);
    setShowNotification(true);
    setTimeout(() => setShowNotification(false), 3000);
  };

  const handleAcceptOffer = (offerId) => {
    const acceptedOffer = jobOffers.find(offer => offer.id === offerId);
    setJobOffers(prev => prev.filter(offer => offer.id !== offerId));
    showNotificationMessage(`✅ Félicitations ! Vous avez accepté l'offre chez ${acceptedOffer?.name}.`);
    setShowJobOffers(false);
  };

  const handleRejectOffer = (offerId) => {
    setJobOffers(prev => prev.filter(offer => offer.id !== offerId));
    showNotificationMessage("❌ Vous avez refusé l'offre.");
  };

  const pendingOffersCount = jobOffers.length;

  const SocialIcons = () => (
    <div className="flex justify-center gap-4 mt-4">
      {socialLinks.facebook && <a href={socialLinks.facebook} target="_blank" rel="noopener noreferrer" className="text-blue-500 hover:text-blue-400 transition-all duration-300 transform hover:scale-110"><i className="fab fa-facebook-f text-xl"></i></a>}
      {socialLinks.instagram && <a href={socialLinks.instagram} target="_blank" rel="noopener noreferrer" className="text-pink-500 hover:text-pink-400 transition-all duration-300 transform hover:scale-110"><i className="fab fa-instagram text-xl"></i></a>}
      {socialLinks.twitter && <a href={socialLinks.twitter} target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:text-blue-300 transition-all duration-300 transform hover:scale-110"><i className="fab fa-twitter text-xl"></i></a>}
      {socialLinks.linkedin && <a href={socialLinks.linkedin} target="_blank" rel="noopener noreferrer" className="text-blue-700 hover:text-blue-600 transition-all duration-300 transform hover:scale-110"><i className="fab fa-linkedin-in text-xl"></i></a>}
      {socialLinks.tiktok && <a href={socialLinks.tiktok} target="_blank" rel="noopener noreferrer" className="text-white hover:text-gray-300 transition-all duration-300 transform hover:scale-110"><i className="fab fa-tiktok text-xl"></i></a>}
    </div>
  );

  return (
    <>
      <style>
        {`
          .navbar-custom {
            background: linear-gradient(135deg, #9b2dff, #7c3aed, #a855f7);
            box-shadow: 0 4px 20px rgba(139, 92, 246, 0.3);
          }
          
          .navbar-custom .nav-link {
            transition: all 0.3s ease;
          }
          
          .navbar-custom .nav-link:hover {
            color: #e9d5ff !important;
            transform: translateY(-2px);
          }
          
          .mobile-menu {
            background: linear-gradient(135deg, #9b2dff, #7c3aed);
          }

          .settings-icon-btn {
            background: rgba(255,255,255,0.15);
            border: 1px solid rgba(255,255,255,0.4);
            border-radius: 8px;
            width: 36px;
            height: 36px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.3s ease;
            margin-right: 12px;
          }
          
          .settings-icon-btn i {
            font-size: 1rem;
          }
          
          .settings-icon-btn:hover {
            background: rgba(255,255,255,0.3);
            transform: scale(1.05) rotate(15deg);
            box-shadow: 0 0 12px rgba(255,255,255,0.3);
          }
          
          /* Sidebar styles */
          @keyframes slideIn {
            from { transform: translateX(-100%); }
            to { transform: translateX(0); }
          }
          
          @keyframes fadeIn {
            from { opacity: 0; }
            to { opacity: 1; }
          }
          
          .sidebar-overlay {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0,0,0,0.7);
            backdrop-filter: blur(5px);
            z-index: 1000;
            animation: fadeIn 0.3s ease;
          }
          
          .sidebar-manager {
            position: fixed;
            top: 0;
            left: 0;
            width: 85%;
            max-width: 400px;
            height: 100vh;
            background: linear-gradient(135deg, #1a1a2e, #16213e);
            z-index: 1001;
            padding: 20px;
            overflow-y: auto;
            animation: slideIn 0.3s ease;
            border-right: 2px solid #a855f7;
            box-shadow: 5px 0 30px rgba(0,0,0,0.5);
          }
          
          .sidebar-manager::-webkit-scrollbar {
            width: 6px;
          }
          
          .sidebar-manager::-webkit-scrollbar-track {
            background: rgba(255,255,255,0.1);
          }
          
          .sidebar-manager::-webkit-scrollbar-thumb {
            background: #a855f7;
            border-radius: 10px;
          }
          
          .profile-image-sidebar {
            width: 80px;
            height: 80px;
            border-radius: 50%;
            margin: 0 auto;
            border: 3px solid #a855f7;
            object-fit: cover;
          }
          
          .cover-image-preview {
            width: 100%;
            height: 100px;
            object-fit: cover;
            border-radius: 15px;
            margin-bottom: 10px;
          }
          
          .profile-name-sidebar {
            color: white;
            font-size: 1.2rem;
            font-weight: bold;
            margin-top: 10px;
          }
          
          .profile-role-sidebar {
            color: #a855f7;
            font-size: 0.85rem;
            margin-top: 5px;
          }
          
          .sidebar-section {
            margin-bottom: 25px;
            padding-bottom: 20px;
            border-bottom: 1px solid rgba(255,255,255,0.1);
          }
          
          .sidebar-title {
            color: #a855f7;
            font-size: 1rem;
            font-weight: bold;
            margin-bottom: 15px;
            display: flex;
            align-items: center;
            gap: 8px;
          }
          
          .sidebar-input {
            width: 100%;
            padding: 10px;
            background: rgba(255,255,255,0.1);
            border: 1px solid rgba(255,255,255,0.2);
            border-radius: 15px;
            color: white;
            margin-bottom: 10px;
          }
          
          .sidebar-input:focus {
            outline: none;
            border-color: #a855f7;
          }
          
          .sidebar-input::placeholder {
            color: rgba(255,255,255,0.4);
          }
          
          .sidebar-label {
            color: rgba(255,255,255,0.7);
            font-size: 0.75rem;
            margin-bottom: 5px;
            display: block;
          }
          
          .file-input {
            width: 100%;
            padding: 8px;
            background: rgba(255,255,255,0.1);
            border: 1px solid rgba(255,255,255,0.2);
            border-radius: 15px;
            color: white;
            margin-bottom: 10px;
            cursor: pointer;
          }
          
          .file-input::-webkit-file-upload-button {
            background: #a855f7;
            border: none;
            padding: 5px 10px;
            border-radius: 10px;
            color: white;
            cursor: pointer;
            margin-right: 10px;
          }
          
          .btn-sidebar {
            background: linear-gradient(135deg, #7c3aed, #6d28d9);
            border: none;
            padding: 10px;
            border-radius: 25px;
            color: white;
            font-weight: bold;
            cursor: pointer;
            width: 100%;
            margin-top: 10px;
            transition: all 0.2s;
          }
          
          .btn-sidebar:hover {
            background: linear-gradient(135deg, #8b5cf6, #7c3aed);
            transform: scale(1.02);
          }
          
          .btn-danger-sidebar {
            background: linear-gradient(135deg, #ef4444, #b91c1c);
          }
          
          /* Job Offers Button in Sidebar */
          .job-offers-btn-sidebar {
            background: linear-gradient(135deg, #f59e0b, #d97706);
            border: none;
            padding: 12px;
            border-radius: 25px;
            color: white;
            font-weight: bold;
            cursor: pointer;
            width: 100%;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 10px;
            margin-bottom: 15px;
            transition: all 0.2s;
            position: relative;
          }
          
          .job-offers-btn-sidebar:hover {
            transform: scale(1.02);
            box-shadow: 0 4px 15px rgba(245, 158, 11, 0.4);
          }
          
          .offers-badge-sidebar {
            position: absolute;
            top: -8px;
            right: -8px;
            background: #ef4444;
            color: white;
            border-radius: 50%;
            width: 22px;
            height: 22px;
            font-size: 11px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: bold;
          }
          
          /* Job Offers Modal */
          .job-offers-modal-overlay {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0, 0, 0, 0.95);
            backdrop-filter: blur(12px);
            z-index: 2000;
            display: flex;
            align-items: center;
            justify-content: center;
            animation: fadeIn 0.3s ease;
          }
          
          .job-offers-modal-container {
            background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
            border-radius: 30px;
            width: 90%;
            max-width: 650px;
            max-height: 85vh;
            overflow-y: auto;
            padding: 25px;
            border: 2px solid #f59e0b;
            box-shadow: 0 0 40px rgba(245, 158, 11, 0.3);
            animation: slideUp 0.4s ease;
          }
          
          @keyframes slideUp {
            from {
              opacity: 0;
              transform: translateY(30px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }
          
          .close-offers-btn {
            float: right;
            background: none;
            border: none;
            color: white;
            font-size: 24px;
            cursor: pointer;
            transition: all 0.2s;
          }
          
          .close-offers-btn:hover {
            transform: scale(1.1);
            color: #ef4444;
          }
          
          .offers-title {
            color: white;
            font-size: 1.3rem;
            text-align: center;
            margin-bottom: 20px;
          }
          
          .offers-list {
            display: flex;
            flex-direction: column;
            gap: 20px;
          }
          
          .no-offers-message {
            text-align: center;
            padding: 40px;
            color: #94a3b8;
          }
          
          .notification-toast {
            position: fixed;
            bottom: 30px;
            right: 30px;
            background: linear-gradient(135deg, #22c55e, #15803d);
            color: white;
            padding: 12px 24px;
            border-radius: 12px;
            z-index: 10001;
            animation: slideInRight 0.3s ease;
            box-shadow: 0 5px 20px rgba(0, 0, 0, 0.2);
            font-weight: 500;
          }
          
          @keyframes slideInRight {
            from {
              transform: translateX(100%);
              opacity: 0;
            }
            to {
              transform: translateX(0);
              opacity: 1;
            }
          }
          
          .modal-overlay-custom {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0,0,0,0.95);
            backdrop-filter: blur(10px);
            z-index: 1100;
            display: flex;
            align-items: center;
            justify-content: center;
          }
          
          .modal-content-custom {
            background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
            border-radius: 30px;
            padding: 25px;
            max-width: 500px;
            width: 90%;
            border: 2px solid #a855f7;
            animation: fadeIn 0.3s ease;
          }
          
          .confirm-buttons {
            display: flex;
            gap: 15px;
            justify-content: center;
            margin-top: 20px;
          }
        `}
      </style>
    
